// Helper function for status badge styling
func orgStatusClass(status app.OrgStatus) string {
	switch status {
	case app.OrgStatusActive:
		return "bg-success-bg text-success border border-success-border"
	case app.OrgStatusError:
		return "bg-error-bg text-error border border-error-border"
	case app.OrgStatusProvisioning:
		return "bg-info-bg text-info border border-info-border"
	case app.OrgStatusDeleting, app.OrgStatusDeprovisioning:
		return "bg-warning-bg text-warning border border-warning-border"
	default:
		return "bg-muted text-muted-foreground border border-border"
	}
}

func buildOrgsPageURL(page int, search string, selectedTags []string) string {
	url := fmt.Sprintf("orgs/table?page=%d", page)
	if search != "" {
		url += fmt.Sprintf("&search=%s", search)
	}
	for _, tag := range selectedTags {
		url += fmt.Sprintf("&tag=%s", tag)
	}
	return url
}

